mapper.select:
SELECT c.*, (SELECT p.cover_url FROM collection_posts cp JOIN posts p ON cp.post_id = p.id WHERE cp.collection_id = c.id AND p.status = 1 ORDER BY cp.created_at DESC LIMIT 1) AS cover_url FROM collections c WHERE c.user_id = #{userId}
AND c.is_public = 1
ORDER BY c.created_at DESC

    EXISTS (
SELECT 1
FROM collection_posts cp
JOIN collections c ON cp.collection_id = c.id
WHERE c.user_id = #{userId}
    AND cp.post_id = #{postId}
    ) AS is_collected;
